def scrape_website(url, use_browser=False, error_callback=None):
    if use_browser:
        from selenium import webdriver
        from selenium.webdriver.chrome.options import Options
        import time
        
        try:
            options = Options()
            options.add_argument("--headless")
            # We add some generic options to make selenium stealthier 
            options.add_argument("--disable-gpu")
            options.add_argument("window-size=1920,1080")
            
            driver = webdriver.Chrome(options=options)
            driver.get(url)
            
            # Sleep to wait for JS frameworks to hydrate
            time.sleep(5)
            
            # Scroll bottom to trigger extra loads if any
            driver.execute_script("window.scrollTo(0, document.body.scrollHeight);")
            time.sleep(2)
            
            html_content = driver.page_source
            driver.quit()
            
            soup = BeautifulSoup(html_content, 'html.parser')
            for script in soup(["script", "style"]):
                script.extract()
            text = soup.get_text(separator=' ', strip=True)
            return text
            
        except Exception as e:
            if error_callback:
                error_callback(f"Selenium Headless Browser fetch failed: {e}")
            return None

    # Fallback to standard fast requests if use_browser=False
    try:
        headers = {
            "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36"
        }
        response = requests.get(url, headers=headers, timeout=12)
        response.raise_for_status()
        soup = BeautifulSoup(response.content, 'html.parser')
        
        for script in soup(["script", "style"]):
            script.extract()
            
        text = soup.get_text(separator=' ', strip=True)
        return text
    except Exception as e:
        if error_callback:
            error_callback(f"Failed to fetch webpage: {e}")
        return None

def invoke_ai_agent(scraped_text, user_prompt, streaming_callback=None):
    if not scraped_text:
        return ""
        
    truncated_text = scraped_text[:18000] # Safe limit for ~8K models
    content = f"Web Content Contexts:\n{truncated_text}\n\nTask: {user_prompt}"
    
    client = OpenAI(
        base_url="https://integrate.api.nvidia.com/v1",
        api_key="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"
    )
    
    full_response = ""
    try:
        completion = client.chat.completions.create(
            model="openai/gpt-oss-20b",
            messages=[{"role": "user", "content": content}],
            temperature=1,
            top_p=1,
            max_tokens=4096,
            stream=bool(streaming_callback)
        )
        
        if streaming_callback:
            for chunk in completion:
                if not getattr(chunk, "choices", None):
                    continue
                reasoning = getattr(chunk.choices[0].delta, "reasoning_content", None)
                if reasoning:
                    pass # Or handle reasoning via callback if wanted
                
                if chunk.choices and chunk.choices[0].delta.content is not None:
                    delta_content = chunk.choices[0].delta.content
                    full_response += delta_content
                    streaming_callback(full_response)
            return full_response
        else:
            return completion.choices[0].message.content
            
    except Exception as e:
        if streaming_callback:
            # Re-raise or notify through callback
            raise e
        else:
            raise e
